INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('bab0e641-2468-4afc-9927-c0bd53cdece3', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'definition', 'Keystone OS, en une phrase', '{"term":"Keystone OS","definition":"Keystone (Keystone OS) est un espace de travail modulaire édité par Protein Studio : il réunit des outils métier dans une seule application web installable (PWA), l''utilisateur active uniquement ce dont il a besoin via le K-Store, l''IA est incluse dans l''abonnement (compteur mensuel, pas de jetons), conçu local d''abord et souverain (données métier dans le navigateur, RGPD). IMPORTANT : Keystone n''est PAS un logiciel d''immobilier ni d''un métier unique — c''est un OS d''outils métier, généraliste et modulaire."}', 'Keystone OS, en une phrase
Keystone OS
Keystone (Keystone OS) est un espace de travail modulaire édité par Protein Studio : il réunit des outils métier dans une seule application web installable (PWA), l''utilisateur active uniquement ce dont il a besoin via le K-Store, l''IA est incluse dans l''abonnement (compteur mensuel, pas de jetons), conçu local d''abord et souverain (données métier dans le navigateur, RGPD). IMPORTANT : Keystone n''est PAS un logiciel d''immobilier ni d''un métier unique — c''est un OS d''outils métier, généraliste et modulaire.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('bab0e641-2468-4afc-9927-c0bd53cdece3', 'Keystone OS, en une phrase', 'Keystone OS, en une phrase
Keystone OS
Keystone (Keystone OS) est un espace de travail modulaire édité par Protein Studio : il réunit des outils métier dans une seule application web installable (PWA), l''utilisateur active uniquement ce dont il a besoin via le K-Store, l''IA est incluse dans l''abonnement (compteur mensuel, pas de jetons), conçu local d''abord et souverain (données métier dans le navigateur, RGPD). IMPORTANT : Keystone n''est PAS un logiciel d''immobilier ni d''un métier unique — c''est un OS d''outils métier, généraliste et modulaire.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('47c15f3f-868a-415a-96c4-c3a3ca956ee6', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Le produit, ses formules et son fonctionnement', '{"statement":"(Repris du guide utilisateur officiel de Keystone.) Le guide pour tirer le meilleur de Keystone. Chaque outil a en plus sa propre aide (bouton « ? »)."}', 'Keystone OS — Le produit, ses formules et son fonctionnement
(Repris du guide utilisateur officiel de Keystone.) Le guide pour tirer le meilleur de Keystone. Chaque outil a en plus sa propre aide (bouton « ? »).', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('47c15f3f-868a-415a-96c4-c3a3ca956ee6', 'Keystone OS — Le produit, ses formules et son fonctionnement', 'Keystone OS — Le produit, ses formules et son fonctionnement
(Repris du guide utilisateur officiel de Keystone.) Le guide pour tirer le meilleur de Keystone. Chaque outil a en plus sa propre aide (bouton « ? »).');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('c5443899-83c6-4421-af02-eb3cd4db0432', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Qu''est-ce que Keystone ?', '{"statement":"Keystone réunit vos outils métier dans un seul espace de travail. Au lieu de jongler entre plusieurs applications et abonnements, vous activez ici uniquement ce dont vous avez besoin — comme des applications sur un téléphone. L''intelligence artificielle est incluse: pas de facturation à la consommation ni de jeton à racheter. Un compteur d''usage équitable évite les abus, et vous gardez la main sur vos données."}', 'Keystone OS — Qu''est-ce que Keystone ?
Keystone réunit vos outils métier dans un seul espace de travail. Au lieu de jongler entre plusieurs applications et abonnements, vous activez ici uniquement ce dont vous avez besoin — comme des applications sur un téléphone. L''intelligence artificielle est incluse: pas de facturation à la consommation ni de jeton à racheter. Un compteur d''usage équitable évite les abus, et vous gardez la main sur vos données.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('c5443899-83c6-4421-af02-eb3cd4db0432', 'Keystone OS — Qu''est-ce que Keystone ?', 'Keystone OS — Qu''est-ce que Keystone ?
Keystone réunit vos outils métier dans un seul espace de travail. Au lieu de jongler entre plusieurs applications et abonnements, vous activez ici uniquement ce dont vous avez besoin — comme des applications sur un téléphone. L''intelligence artificielle est incluse: pas de facturation à la consommation ni de jeton à racheter. Un compteur d''usage équitable évite les abus, et vous gardez la main sur vos données.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('8897a65b-c3c3-49c2-bd80-61b80f800c40', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Votre tableau de bord', '{"statement":"Vos outils apparaissent en tuiles sur l''accueil. Un clic ouvre l''outil en plein écran; la flèche en haut à gauche vous ramène au tableau de bord. Réorganiser: glissez-déposez les tuiles pour les ranger à votre goût. Renommer ou retirer: appui long (mobile) ou clic droit (ordinateur) sur une tuile."}', 'Keystone OS — Votre tableau de bord
Vos outils apparaissent en tuiles sur l''accueil. Un clic ouvre l''outil en plein écran; la flèche en haut à gauche vous ramène au tableau de bord. Réorganiser: glissez-déposez les tuiles pour les ranger à votre goût. Renommer ou retirer: appui long (mobile) ou clic droit (ordinateur) sur une tuile.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('8897a65b-c3c3-49c2-bd80-61b80f800c40', 'Keystone OS — Votre tableau de bord', 'Keystone OS — Votre tableau de bord
Vos outils apparaissent en tuiles sur l''accueil. Un clic ouvre l''outil en plein écran; la flèche en haut à gauche vous ramène au tableau de bord. Réorganiser: glissez-déposez les tuiles pour les ranger à votre goût. Renommer ou retirer: appui long (mobile) ou clic droit (ordinateur) sur une tuile.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('7f876e7f-9562-4941-91f1-7d2429f9500a', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Ajouter ou retirer des outils', '{"statement":"Le K-Store (bouton + ou l''icône boutique) liste tous les outils disponibles dans votre formule. Ouvrez-le pour ajouter un outil à votre tableau de bord, ou le retirer si vous ne l''utilisez plus — votre travail n''est jamais perdu, l''outil revient avec ses données quand vous le réactivez."}', 'Keystone OS — Ajouter ou retirer des outils
Le K-Store (bouton + ou l''icône boutique) liste tous les outils disponibles dans votre formule. Ouvrez-le pour ajouter un outil à votre tableau de bord, ou le retirer si vous ne l''utilisez plus — votre travail n''est jamais perdu, l''outil revient avec ses données quand vous le réactivez.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('7f876e7f-9562-4941-91f1-7d2429f9500a', 'Keystone OS — Ajouter ou retirer des outils', 'Keystone OS — Ajouter ou retirer des outils
Le K-Store (bouton + ou l''icône boutique) liste tous les outils disponibles dans votre formule. Ouvrez-le pour ajouter un outil à votre tableau de bord, ou le retirer si vous ne l''utilisez plus — votre travail n''est jamais perdu, l''outil revient avec ses données quand vous le réactivez.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('d05b3d5c-a7a1-48e6-8b00-f67490b42d3a', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Vos crédits IA', '{"statement":"Les fonctions d''intelligence artificielle puisent dans un compteur mensuel inclus dans votre abonnement. Il se remet à zéro le 1er de chaque mois. Vous suivez votre consommation dans la section « Crédits IA » de ces réglages; si besoin, un pack ponctuel peut être ajouté. Beaucoup d''actions sont gratuites: lecture vocale, dictée, navigation, et tout ce qui ne fait pas appel à l''IA."}', 'Keystone OS — Vos crédits IA
Les fonctions d''intelligence artificielle puisent dans un compteur mensuel inclus dans votre abonnement. Il se remet à zéro le 1er de chaque mois. Vous suivez votre consommation dans la section « Crédits IA » de ces réglages; si besoin, un pack ponctuel peut être ajouté. Beaucoup d''actions sont gratuites: lecture vocale, dictée, navigation, et tout ce qui ne fait pas appel à l''IA.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('d05b3d5c-a7a1-48e6-8b00-f67490b42d3a', 'Keystone OS — Vos crédits IA', 'Keystone OS — Vos crédits IA
Les fonctions d''intelligence artificielle puisent dans un compteur mensuel inclus dans votre abonnement. Il se remet à zéro le 1er de chaque mois. Vous suivez votre consommation dans la section « Crédits IA » de ces réglages; si besoin, un pack ponctuel peut être ajouté. Beaucoup d''actions sont gratuites: lecture vocale, dictée, navigation, et tout ce qui ne fait pas appel à l''IA.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('97ca1264-ad79-43a5-8825-4402edbe918d', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Vos données & votre confidentialité', '{"statement":"Keystone est conçu local d''abord: vos clés et vos données métier restent dans votre navigateur, sur votre appareil. Seul votre profil (prénom, photo, préférences) est synchronisé, chiffré, pour vous retrouver d''un appareil à l''autre. Le détail complet et le bouton « droit à l''oubli » sont dans la section « RGPD & Données » ci-dessous."}', 'Keystone OS — Vos données & votre confidentialité
Keystone est conçu local d''abord: vos clés et vos données métier restent dans votre navigateur, sur votre appareil. Seul votre profil (prénom, photo, préférences) est synchronisé, chiffré, pour vous retrouver d''un appareil à l''autre. Le détail complet et le bouton « droit à l''oubli » sont dans la section « RGPD & Données » ci-dessous.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('97ca1264-ad79-43a5-8825-4402edbe918d', 'Keystone OS — Vos données & votre confidentialité', 'Keystone OS — Vos données & votre confidentialité
Keystone est conçu local d''abord: vos clés et vos données métier restent dans votre navigateur, sur votre appareil. Seul votre profil (prénom, photo, préférences) est synchronisé, chiffré, pour vous retrouver d''un appareil à l''autre. Le détail complet et le bouton « droit à l''oubli » sont dans la section « RGPD & Données » ci-dessous.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('a43b99f0-9bfe-4993-890a-87e9f7cd24dc', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Installer Keystone sur votre appareil', '{"statement":"Keystone est une application web: rien à télécharger sur un store. Pour l''avoir à portée de main: Sur mobile: menu du navigateur → « Ajouter à l''écran d''accueil ». Sur ordinateur: icône d''installation dans la barre d''adresse, ou menu du navigateur → « Installer ». Une fois installée, elle s''ouvre comme une vraie app et reste consultable même hors connexion pour l''essentiel."}', 'Keystone OS — Installer Keystone sur votre appareil
Keystone est une application web: rien à télécharger sur un store. Pour l''avoir à portée de main: Sur mobile: menu du navigateur → « Ajouter à l''écran d''accueil ». Sur ordinateur: icône d''installation dans la barre d''adresse, ou menu du navigateur → « Installer ». Une fois installée, elle s''ouvre comme une vraie app et reste consultable même hors connexion pour l''essentiel.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('a43b99f0-9bfe-4993-890a-87e9f7cd24dc', 'Keystone OS — Installer Keystone sur votre appareil', 'Keystone OS — Installer Keystone sur votre appareil
Keystone est une application web: rien à télécharger sur un store. Pour l''avoir à portée de main: Sur mobile: menu du navigateur → « Ajouter à l''écran d''accueil ». Sur ordinateur: icône d''installation dans la barre d''adresse, ou menu du navigateur → « Installer ». Une fois installée, elle s''ouvre comme une vraie app et reste consultable même hors connexion pour l''essentiel.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('b7b8c284-c0bd-4d73-8634-f11ce55a4011', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Les formules', '{"statement":"Votre formule détermine les outils accessibles: Démo (découverte), Starter, Pro et Max (accès complet). Le badge coloré d''un outil dans le K-Store indique la formule requise. Votre statut, votre clé et votre renouvellement sont dans la section « Ma Licence »."}', 'Keystone OS — Les formules
Votre formule détermine les outils accessibles: Démo (découverte), Starter, Pro et Max (accès complet). Le badge coloré d''un outil dans le K-Store indique la formule requise. Votre statut, votre clé et votre renouvellement sont dans la section « Ma Licence ».', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('b7b8c284-c0bd-4d73-8634-f11ce55a4011', 'Keystone OS — Les formules', 'Keystone OS — Les formules
Votre formule détermine les outils accessibles: Démo (découverte), Starter, Pro et Max (accès complet). Le badge coloré d''un outil dans le K-Store indique la formule requise. Votre statut, votre clé et votre renouvellement sont dans la section « Ma Licence ».');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('9fb5f5e1-4387-4eec-9737-f06629068f59', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Les offres — 3 plans (c''est ainsi que Keystone se vend)', '{"statement":"Keystone ne se vend pas application par application. Le client choisit un plan, puis active le nombre d''applications que ce plan autorise (3, 5, ou toutes). L''IA (crédits mensuels inclus) et l''hébergement européen font partie du plan — pas de surcoût à l''usage."}', 'Keystone OS — Les offres — 3 plans (c''est ainsi que Keystone se vend)
Keystone ne se vend pas application par application. Le client choisit un plan, puis active le nombre d''applications que ce plan autorise (3, 5, ou toutes). L''IA (crédits mensuels inclus) et l''hébergement européen font partie du plan — pas de surcoût à l''usage.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('9fb5f5e1-4387-4eec-9737-f06629068f59', 'Keystone OS — Les offres — 3 plans (c''est ainsi que Keystone se vend)', 'Keystone OS — Les offres — 3 plans (c''est ainsi que Keystone se vend)
Keystone ne se vend pas application par application. Le client choisit un plan, puis active le nombre d''applications que ce plan autorise (3, 5, ou toutes). L''IA (crédits mensuels inclus) et l''hébergement européen font partie du plan — pas de surcoût à l''usage.');
