INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('6ca06ca9-5ab5-4d9c-9c5c-051bb467bc93', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Gouvernance, RGPD & confiance', '{"statement":"Ce que Keystone garantit côté confiance — de quoi rassurer un prospect, sans entrer dans la technique: RGPD & données. Keystone est conçu local d''abord: les données métier et les clés de l''utilisateur restent sur son appareil; seul le profil (prénom, photo, préférences) est synchronisé et chiffré. Un droit à l''oubli (purge des données) est disponible. L''éditeur est une société française identifiée (Protein Keystone Studio). Les mentions légales, la politique de confidentialité et une page sécurité sont publiées. Prévu à la feuille de route: un export RGPD complet en un clic; aujourd''hui, chaque outil permet déjà d''exporter ses propres données. Avis & commentaires. Chaque outil peut recevoir une note (étoiles) de ses utilisateurs. Les retours sont agrégés de façon anonyme — aucune donnée nominative n''est exposée — et servent à prioriser les améliorations. Posture. L''IA est incluse (pas de revente de données, pas de facturation au jeton, compteur d''usage équitable). Souveraineté et clarté sur les données sont des arguments de vente à part entière. (Le back-office d''administration — licences, réglages internes — est hors de ce document: il ne concerne ni le client ni un plan marketing.)"}', 'Keystone OS — Gouvernance, RGPD & confiance
Ce que Keystone garantit côté confiance — de quoi rassurer un prospect, sans entrer dans la technique: RGPD & données. Keystone est conçu local d''abord: les données métier et les clés de l''utilisateur restent sur son appareil; seul le profil (prénom, photo, préférences) est synchronisé et chiffré. Un droit à l''oubli (purge des données) est disponible. L''éditeur est une société française identifiée (Protein Keystone Studio). Les mentions légales, la politique de confidentialité et une page sécurité sont publiées. Prévu à la feuille de route: un export RGPD complet en un clic; aujourd''hui, chaque outil permet déjà d''exporter ses propres données. Avis & commentaires. Chaque outil peut recevoir une note (étoiles) de ses utilisateurs. Les retours sont agrégés de façon anonyme — aucune donnée nominative n''est exposée — et servent à prioriser les améliorations. Posture. L''IA est incluse (pas de revente de données, pas de facturation au jeton, compteur d''usage équitable). Souveraineté et clarté sur les données sont des arguments de vente à part entière. (Le back-office d''administration — licences, réglages internes — est hors de ce document: il ne concerne ni le client ni un plan marketing.)', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('6ca06ca9-5ab5-4d9c-9c5c-051bb467bc93', 'Keystone OS — Gouvernance, RGPD & confiance', 'Keystone OS — Gouvernance, RGPD & confiance
Ce que Keystone garantit côté confiance — de quoi rassurer un prospect, sans entrer dans la technique: RGPD & données. Keystone est conçu local d''abord: les données métier et les clés de l''utilisateur restent sur son appareil; seul le profil (prénom, photo, préférences) est synchronisé et chiffré. Un droit à l''oubli (purge des données) est disponible. L''éditeur est une société française identifiée (Protein Keystone Studio). Les mentions légales, la politique de confidentialité et une page sécurité sont publiées. Prévu à la feuille de route: un export RGPD complet en un clic; aujourd''hui, chaque outil permet déjà d''exporter ses propres données. Avis & commentaires. Chaque outil peut recevoir une note (étoiles) de ses utilisateurs. Les retours sont agrégés de façon anonyme — aucune donnée nominative n''est exposée — et servent à prioriser les améliorations. Posture. L''IA est incluse (pas de revente de données, pas de facturation au jeton, compteur d''usage équitable). Souveraineté et clarté sur les données sont des arguments de vente à part entière. (Le back-office d''administration — licences, réglages internes — est hors de ce document: il ne concerne ni le client ni un plan marketing.)');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('c9ae4a5d-424d-4de0-99d7-7ba0fd68695e', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Le Living Layer', '{"statement":"Le Living Layer est une barre ambiante en haut du tableau de bord. Au lieu d''un dashboard figé, il fait remonter en continu de vrais signaux métier issus des outils actifs: les questions auxquelles le Smart Agent n''a pas su répondre (trous de savoir à combler), les réponses reçues, les rappels Keynapse qui arrivent à échéance, les alertes de visibilité Sentinel, le suivi des QR les plus scannés. Une alerte importante reste « collante » tant qu''elle n''est pas traitée. C''est ce qui transforme Keystone d''une boîte à outils en un poste de pilotage qui dit à l''utilisateur quoi faire ensuite."}', 'Keystone OS — Le Living Layer
Le Living Layer est une barre ambiante en haut du tableau de bord. Au lieu d''un dashboard figé, il fait remonter en continu de vrais signaux métier issus des outils actifs: les questions auxquelles le Smart Agent n''a pas su répondre (trous de savoir à combler), les réponses reçues, les rappels Keynapse qui arrivent à échéance, les alertes de visibilité Sentinel, le suivi des QR les plus scannés. Une alerte importante reste « collante » tant qu''elle n''est pas traitée. C''est ce qui transforme Keystone d''une boîte à outils en un poste de pilotage qui dit à l''utilisateur quoi faire ensuite.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('c9ae4a5d-424d-4de0-99d7-7ba0fd68695e', 'Keystone OS — Le Living Layer', 'Keystone OS — Le Living Layer
Le Living Layer est une barre ambiante en haut du tableau de bord. Au lieu d''un dashboard figé, il fait remonter en continu de vrais signaux métier issus des outils actifs: les questions auxquelles le Smart Agent n''a pas su répondre (trous de savoir à combler), les réponses reçues, les rappels Keynapse qui arrivent à échéance, les alertes de visibilité Sentinel, le suivi des QR les plus scannés. Une alerte importante reste « collante » tant qu''elle n''est pas traitée. C''est ce qui transforme Keystone d''une boîte à outils en un poste de pilotage qui dit à l''utilisateur quoi faire ensuite.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('476f9c05-33da-48d4-9399-1ea019861b4c', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keystone OS — Comment les outils travaillent ensemble', '{"statement":"Les outils Keystone ne sont pas des silos: ils se passent le relais. Les enchaînements clés à connaître pour vendre: La chaîne de contenu: Brainstorming fait émerger les idées et tranche les angles → Ghost Writer rédige et met en forme → Social Manager diffuse sur les réseaux. Une idée devient une publication sans changer d''outil. Du physique au conversationnel: un Smart Dynamic QR posé sur une vitrine, un produit ou une chambre d''hôtel ouvre directement un Smart Agent (ou un QR Concierge) qui répond au visiteur — sans app à installer, à l''écrit ou à la voix. La visibilité qui remonte: Sentinel surveille la présence web et l''apparition dans les réponses des IA, et pousse ses alertes dans le Living Layer. Le socle commun: identité de marque (Key Brand), collecte (Key Form), notes et rappels (Keynapse) et transmission de secrets (Missive) servent tous les autres outils. La marque définie dans Key Brand peut habiller les supports produits ailleurs. Le tout dans un seul espace, une seule connexion, un seul abonnement — c''est l''argument central face à quelqu''un qui jongle avec 6 abonnements séparés."}', 'Keystone OS — Comment les outils travaillent ensemble
Les outils Keystone ne sont pas des silos: ils se passent le relais. Les enchaînements clés à connaître pour vendre: La chaîne de contenu: Brainstorming fait émerger les idées et tranche les angles → Ghost Writer rédige et met en forme → Social Manager diffuse sur les réseaux. Une idée devient une publication sans changer d''outil. Du physique au conversationnel: un Smart Dynamic QR posé sur une vitrine, un produit ou une chambre d''hôtel ouvre directement un Smart Agent (ou un QR Concierge) qui répond au visiteur — sans app à installer, à l''écrit ou à la voix. La visibilité qui remonte: Sentinel surveille la présence web et l''apparition dans les réponses des IA, et pousse ses alertes dans le Living Layer. Le socle commun: identité de marque (Key Brand), collecte (Key Form), notes et rappels (Keynapse) et transmission de secrets (Missive) servent tous les autres outils. La marque définie dans Key Brand peut habiller les supports produits ailleurs. Le tout dans un seul espace, une seule connexion, un seul abonnement — c''est l''argument central face à quelqu''un qui jongle avec 6 abonnements séparés.', 'validated', 'import', 'apps:keystone-os', 'fr');
INSERT INTO kortex_units_fts (unit_id, title, body_text) VALUES ('476f9c05-33da-48d4-9399-1ea019861b4c', 'Keystone OS — Comment les outils travaillent ensemble', 'Keystone OS — Comment les outils travaillent ensemble
Les outils Keystone ne sont pas des silos: ils se passent le relais. Les enchaînements clés à connaître pour vendre: La chaîne de contenu: Brainstorming fait émerger les idées et tranche les angles → Ghost Writer rédige et met en forme → Social Manager diffuse sur les réseaux. Une idée devient une publication sans changer d''outil. Du physique au conversationnel: un Smart Dynamic QR posé sur une vitrine, un produit ou une chambre d''hôtel ouvre directement un Smart Agent (ou un QR Concierge) qui répond au visiteur — sans app à installer, à l''écrit ou à la voix. La visibilité qui remonte: Sentinel surveille la présence web et l''apparition dans les réponses des IA, et pousse ses alertes dans le Living Layer. Le socle commun: identité de marque (Key Brand), collecte (Key Form), notes et rappels (Keynapse) et transmission de secrets (Missive) servent tous les autres outils. La marque définie dans Key Brand peut habiller les supports produits ailleurs. Le tout dans un seul espace, une seule connexion, un seul abonnement — c''est l''argument central face à quelqu''un qui jongle avec 6 abonnements séparés.');
